import parse_date from "stdlib/datetime"

fn parse_dates(text: Text) -> [Text, Text] {
    dates = split(text, ", ")
    return [dates[0], dates[1]]
}

fn calculate_days(date1: Text, date2: Text) -> Number {
    date1 = parse_date(date1)
    date2 = parse_date(date2)
    return (date2 - date1).days
}

fn is_reasonable(days: Number) -> Boolean {
    if days < 30 { return true }
    if days > 90 { return false }
    return true
}

entry main(text: Text) {
    [meeting, deadline] = parse_dates(text)
    days = calculate_days(meeting, deadline)
    return join([to_text(days), " ", is_reasonable(days) ? "reasonable" : "unreasonable"], "")
}

