import stdlib.math as math

fn calculate_std_dev(nums: Number[]) -> Number {
    mean = average(nums)
    variance = 0.0
    for n in nums {
        variance += (n - mean) * (n - mean)
    }
    return sqrt(variance / length(nums))
}

fn is_highly_variable(std_dev: Number, mean: Number) -> Text {
    if std_dev > 2 * mean {
        return "highly variable"
    } else {
        return "not highly variable"
    }
}

entry main(x: Text) {
    nums = [10, 12, 23, 23, 16, 23, 21, 16]
    std_dev = calculate_std_dev(nums)
    result = is_highly_variable(std_dev, average(nums))
    return join([to_text(std_dev), " ", to_text(average(nums)), " ", result], "")
}

