pure fn fibonacci(n: Number) -> [Number] {
    if n <= 1 { return [0, 1] }
    fib = []
    a = 0
    b = 1
    for i in range(2, n + 1) {
        fib = append(fib, b)
        a, b = b, a + b
    }
    return fib
}

